def capital_gain_loss(stocks: pd.DataFrame) -> pd.DataFrame:
    stocks['price'] = stocks.apply(lambda r: -r.price if r.operation == 'Buy' else r.price, axis=1)
    return stocks.groupby('stock_name')['price'].sum().reset_index(name='capital_gain_loss')

