class Solution:
    def maxNumOfSubstrings(self, s: str) -> List[str]:
        # 1. Find the first and last occurrence for each character
        first = {c: i for i, c in enumerate(s[::-1])}
        first = {c: len(s) - 1 - i for c, i in first.items()}
        last = {c: i for i, c in enumerate(s)}

        # Correcting first occurrence map (above logic was slightly inverted for 'first')
        first = {}
        for i, c in enumerate(s):
            if c not in first: first[c] = i

        def get_range(i):
            # Expand the range for the character at index i
            l, r = first[s[i]], last[s[i]]
            curr = l
            while curr <= r:
                cl, cr = first[s[curr]], last[s[curr]]
                if cl < l: return -1, -1 # Invalid because it breaks the leftmost boundary we started with
                l, r = min(l, cl), max(r, cr)
                curr += 1
            return l, r

        # 2. Find all valid ranges
        ranges = []
        for i in range(26):
            char = chr(ord('a') + i)
            if char in first:
                l, r = get_range(first[char])
                if l != -1:
                    ranges.append([l, r])

        # 3. Greedy selection of non-overlapping intervals (Activity Selection variant)
        # Sort by end time to maximize number of intervals
        ranges.sort(key=lambda x: x[1])
        res = []
        last_end = -1
        for l, r in ranges:
            if l > last_end:
                res.append(s[l:r+1])
                last_end = r
        return res

