class Solution:
    def countPairs(self, root: TreeNode, distance: int) -> int:
        def dfs(root, cnt, i):
            if root is None or i >= distance:
                return
            if root.left is None and root.right is None:
                cnt[i] += 1
                return
            dfs(root.left, cnt, i + 1)
            dfs(root.right, cnt, i + 1)

        if root is None:
            return 0
        ans = self.countPairs(root.left, distance) + self.countPairs(
            root.right, distance
        )
        cnt1 = Counter()
        cnt2 = Counter()
        dfs(root.left, cnt1, 1)
        dfs(root.right, cnt2, 1)

        for k1, v1 in cnt1.items():
            for k2, v2 in cnt2.items():
                if k1 + k2 <= distance:
                    ans += v1 * v2
        return ans

class Solution:
    def getLengthOfOptimalCompression(self, s: str, k: int) -> int:
        # DP with memoization
        # state: (index, remaining_k, last_char, last_char_count)
        memo = {}

        def get_len(cnt):
            if cnt == 0: return 0
            if cnt == 1: return 1
            if cnt < 10: return 2
            if cnt < 100: return 3
            return 4

        def solve(idx, rem_k, last_c, last_cnt):
            state = (idx, rem_k, last_c, last_cnt)
            if state in memo: return memo[state]
            if rem_k < 0: return float('inf')
            if idx == len(s): return 0

            # Option 1: Delete current character
            res = solve(idx + 1, rem_k - 1, last_c, last_cnt)

            # Option 2: Keep current character
            if s[idx] == last_c:
                # Same as previous, check if length increases (e.g., from 1 to 2, 9 to 10, 99 to 100)
                incr = 0
                if last_cnt in [1, 9, 99]:
                    incr = 1
                res = min(res, incr + solve(idx + 1, rem_k, last_c, last_cnt + 1))
            else:
                # Different character, new run starts
                res = min(res, 1 + solve(idx + 1, rem_k, s[idx], 1))

            memo[state] = res
            return res

        return solve(0, k, '', 0)

