class Solution:
    def isPrintable(self, targetGrid: List[List[int]]) -> bool:
        m, n = len(targetGrid), len(targetGrid[0])
        # Find boundaries for each color
        pos = {}
        for r in range(m):
            for c in range(n):
                color = targetGrid[r][c]
                if color not in pos:
                    pos[color] = [r, r, c, c] # minR, maxR, minC, maxC
                else:
                    pos[color][0] = min(pos[color][0], r)
                    pos[color][1] = max(pos[color][1], r)
                    pos[color][2] = min(pos[color][2], c)
                    pos[color][3] = max(pos[color][3], c)

        # Build adjacency list for topological sort
        adj = collections.defaultdict(set)
        for color, (minR, maxR, minC, maxC) in pos.items():
            for r in range(minR, maxR + 1):
                for c in range(minC, maxC + 1):
                    if targetGrid[r][c] != color:
                        adj[color].add(targetGrid[r][c])

        # Cycle detection using DFS (standard 3-color approach)
        visited = {} # color: 0=visiting, 1=visited
        def has_cycle(u):
            visited[u] = 0
            for v in adj[u]:
                if v in visited:
                    if visited[v] == 0: return True
                else:
                    if has_cycle(v): return True
            visited[u] = 1
            return False

        for color in pos:
            if color not in visited:
                if has_cycle(color): return False
        return True

