class Solution:
    def largestMagicSquare(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        rowsum = [[0] * (n + 1) for _ in range(m + 1)]
        colsum = [[0] * (n + 1) for _ in range(m + 1)]
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                rowsum[i][j] = rowsum[i][j - 1] + grid[i - 1][j - 1]
                colsum[i][j] = colsum[i - 1][j] + grid[i - 1][j - 1]

        def check(x1, y1, x2, y2):
            val = rowsum[x1 + 1][y2 + 1] - rowsum[x1 + 1][y1]
            for i in range(x1 + 1, x2 + 1):
                if rowsum[i + 1][y2 + 1] - rowsum[i + 1][y1] != val:
                    return False
            for j in range(y1, y2 + 1):
                if colsum[x2 + 1][j + 1] - colsum[x1][j + 1] != val:
                    return False
            s, i, j = 0, x1, y1
            while i <= x2:
                s += grid[i][j]
                i += 1
                j += 1
            if s != val:
                return False
            s, i, j = 0, x1, y2
            while i <= x2:
                s += grid[i][j]
                i += 1
                j -= 1
            if s != val:
                return False
            return True

        for k in range(min(m, n), 1, -1):
            i = 0
            while i + k - 1 < m:
                j = 0
                while j + k - 1 < n:
                    i2, j2 = i + k - 1, j + k - 1
                    if check(i, j, i2, j2):
                        return k
                    j += 1
                i += 1
        return 1

class Solution:
    def minOperationsToFlip(self, expression: str) -> int:
        # Pair: (value, cost_to_flip)
        # We use a stack to process parentheses and left-to-right operations
        # Since precedence is just left-to-right (after parens), we can process sequentially.

        def calc(v1, c1, v2, c2, op):
            if op == '&':
                if v1 == 1 and v2 == 1:
                    return 1, min(c1, c2)
                elif v1 == 0 and v2 == 0:
                    return 0, 1 + min(c1, c2)
                else: # 0 & 1 or 1 & 0
                    return 0, 1
            else: # op == '|'
                if v1 == 0 and v2 == 0:
                    return 0, min(c1, c2)
                elif v1 == 1 and v2 == 1:
                    return 1, 1 + min(c1, c2)
                else: # 1 | 0 or 0 | 1
                    return 1, 1

        stack = [[]]
        for c in expression:
            if c == '(':
                stack.append([])
            elif c == ')':
                v, cost = stack.pop()
                if not stack[-1]:
                    stack[-1] = [v, cost]
                else:
                    op = stack[-1].pop()
                    prev_v, prev_cost = stack[-1].pop()
                    stack[-1] = list(calc(prev_v, prev_cost, v, cost, op))
            elif c in '&|':
                stack[-1].append(c)
            else:
                v, cost = int(c), 1
                if not stack[-1]:
                    stack[-1] = [v, cost]
                else:
                    op = stack[-1].pop()
                    prev_v, prev_cost = stack[-1].pop()
                    stack[-1] = list(calc(prev_v, prev_cost, v, cost, op))

        return stack[0][1]

