    def canMerge(self, trees: List[TreeNode]) -> Optional[TreeNode]:
        # 1. Map roots to nodes for fast access
        nodes = {t.val: t for t in trees}
        # 2. Track in-degree of each potential root (how many times it's a leaf)
        indegree = collections.defaultdict(int)
        for t in trees:
            if t.left:
                indegree[t.left.val] += 1
            if t.right:
                indegree[t.right.val] += 1

        # 3. Find the unique root (in-degree 0 among given roots)
        root_node = None
        for t in trees:
            if indegree[t.val] == 0:
                if root_node: return None # Multiple roots impossible
                root_node = t

        if not root_node: return None

        # 4. Traverse and merge
        used = set()
        def traverse(node, min_val, max_val):
            if not node: return True
            if not (min_val < node.val < max_val): return False

            # If it's a leaf, try to merge
            if not node.left and not node.right:
                if node.val in nodes and node.val not in used:
                    t = nodes[node.val]
                    used.add(node.val)
                    node.left = t.left
                    node.right = t.right
                    # Validate the merged children
                    return traverse(node.left, min_val, node.val) and traverse(node.right, node.val, max_val)

            return traverse(node.left, min_val, node.val) and traverse(node.right, node.val, max_val)

        used.add(root_node.val)
        if traverse(root_node, float('-inf'), float('inf')) and len(used) == len(trees):
            return root_node
        return None

