class Solution:
    def smallestChair(self, times: List[List[int]], targetFriend: int) -> int:
        n = len(times)
        for i in range(n):
            times[i].append(i)
        times.sort()
        idle = list(range(n))
        heapify(idle)
        busy = []
        for arrival, leaving, i in times:
            while busy and busy[0][0] <= arrival:
                heappush(idle, heappop(busy)[1])
            j = heappop(idle)
            if i == targetFriend:
                return j
            heappush(busy, (leaving, j))

class Solution:
    def maxGeneticDifference(self, parents: List[int], queries: List[List[int]]) -> List[int]:
        # Trie to find max XOR efficiently
        class TrieNode:
            def __init__(self):
                self.children = {}
                self.count = 0

        def insert(val, delta):
            node = root
            for i in range(19, -1, -1):
                bit = (val >> i) & 1
                if bit not in node.children: node.children[bit] = TrieNode()
                node = node.children[bit]
                node.count += delta

        def query_max(val):
            node = root
            res = 0
            for i in range(19, -1, -1):
                bit = (val >> i) & 1
                target = 1 - bit
                if target in node.children and node.children[target].count > 0:
                    res |= (1 << i)
                    node = node.children[target]
                else:
                    node = node.children[bit]
            return res

        # Build graph and map queries to nodes
        n = len(parents)
        adj = collections.defaultdict(list)
        root_node = -1
        for i, p in enumerate(parents):
            if p == -1: root_node = i
            else: adj[p].append(i)

        query_map = collections.defaultdict(list)
        for i, (node, val) in enumerate(queries):
            query_map[node].append((val, i))

        # DFS to process queries
        ans = [0] * len(queries)
        root = TrieNode()

        def dfs(u):
            insert(u, 1)
            for val, i in query_map[u]:
                ans[i] = query_max(val)
            for v in adj[u]:
                dfs(v)
            insert(u, -1)

        dfs(root_node)
        return ans

